[
  {
    "file": "src/vs/editor/common/core/position.ts",
    "line": 103,
    "severity": "critical",
    "description": "The isBefore() method uses <= instead of < for the column comparison when positions are on the same line. The docstring states 'If the two positions are equal, the result will be false', meaning equal positions should return false. However, when a.column == b.column, the current condition 'a.column <= b.column' returns true, violating the contract. This breaks position ordering across the entire editor (selections, cursor movement, undo/redo).",
    "fix_patch": "--- a/src/vs/editor/common/core/position.ts
+++ b/src/vs/editor/common/core/position.ts
@@ -100,7 +100,7 @@
 	if (b.lineNumber < a.lineNumber) {
 		return false;
 	}
-	return a.column <= b.column;
+	return a.column < b.column;
 }

 	/**
"
  },
  {
    "file": "src/vs/editor/common/core/range.ts",
    "line": 97,
    "severity": "critical",
    "description": "The containsPosition() method uses >= instead of > for the end column check. The docstring states 'If the position is at the edges, will return true', but the current code returns false when position.column == range.endColumn (at the boundary). This breaks boundary detection in find/replace, decorations, code lens, and bracket matching that rely on inclusive edge containment.",
    "fix_patch": "--- a/src/vs/editor/common/core/range.ts
+++ b/src/vs/editor/common/core/range.ts
@@ -94,7 +94,7 @@
 	if (position.lineNumber === range.startLineNumber && position.column < range.startColumn) {
 		return false;
 	}
-	if (position.lineNumber === range.endLineNumber && position.column >= range.endColumn) {
+	if (position.lineNumber === range.endLineNumber && position.column > range.endColumn) {
 		return false;
 	}
 	return true;
"
  },
  {
    "file": "src/vs/base/common/strings.ts",
    "line": 227,
    "severity": "critical",
    "description": "The createRegExp() function inverts the matchCase logic. The regex 'i' flag means case-INSENSITIVE matching. When matchCase is true, we should NOT include 'i' (case-sensitive). When matchCase is false, we should include 'i' (case-insensitive). The current code does the opposite, causing all search operations to have inverted case sensitivity. This breaks find/replace, completions, hover, and all language features that use regex creation.",
    "fix_patch": "--- a/src/vs/base/common/strings.ts
+++ b/src/vs/base/common/strings.ts
@@ -224,7 +224,7 @@
 	if (options.global) {
 		modifiers += 'g';
 	}
-	if (options.matchCase) {
+	if (!options.matchCase) {
 		modifiers += 'i';
 	}
 	if (options.multiline) {
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 490,
    "severity": "critical",
    "description": "The isValidMatch() function uses OR (||) instead of AND (&&) for word boundary validation. For whole-word matching, BOTH the left AND right boundaries must be valid word boundaries. The current OR operator causes partial word matches to be incorrectly accepted. This breaks whole-word search, find-replace with whole-word flag, and affects bracket matching that relies on word boundary detection.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -487,7 +487,7 @@
 export function isValidMatch(wordSeparators: WordCharacterClassifier, text: string, textLength: number, matchStartIndex: number, matchLength: number): boolean {
 	return (
 		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
-		|| rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		&& rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
 	);
 }

"
  },
  {
    "file": "src/vs/editor/common/languageFeatureRegistry.ts",
    "line": 195,
    "severity": "critical",
    "description": "The _compareByScoreAndTime() sorting comparator has inverted score comparison logic. The task explicitly states 'Higher scores should appear first', but the current code returns -1 when a._score < b._score, causing lower-scored providers to appear first. This inverts the provider priority ordering, causing less-relevant language features (completions, hover, diagnostics) to be prioritized over more-relevant ones.",
    "fix_patch": "--- a/src/vs/editor/common/languageFeatureRegistry.ts
+++ b/src/vs/editor/common/languageFeatureRegistry.ts
@@ -193,10 +193,10 @@
 	private static _compareByScoreAndTime(a: Entry<any>, b: Entry<any>): number {
 		if (a._score < b._score) {
-			return -1;
+			return 1;
 		} else if (a._score > b._score) {
-			return 1;
+			return -1;
 		}

 		// De-prioritize built-in providers
"
  }
]

